// Données reçues du frontend
const body = $input.first().json.body;
const { intervention_id, client_id, client_first_name, client_phone, org_id } = body;

const REDIRECT_BASE = 'https://odspcxgafcqxjzrarsqf.supabase.co/functions/v1/avis-redirect';

// Formater le numéro FR pour Twilio (+33...)
let phone = (client_phone || '').replace(/[\s.-]/g, '');
if (phone.startsWith('0')) {
  phone = '+33' + phone.substring(1);
} else if (phone.startsWith('33')) {
  phone = '+' + phone;
} else if (!phone.startsWith('+')) {
  phone = '+33' + phone;
}

// Prénom formaté
const prenom = client_first_name
  ? client_first_name.charAt(0).toUpperCase() + client_first_name.slice(1).toLowerCase()
  : '';
const salutation = prenom ? `Bonjour ${prenom}` : 'Bonjour';

// Lien placeholder (sera remplacé après pre-log)
const trackingPlaceholder = `${REDIRECT_BASE}?log_id=PENDING`;

return [{
  json: {
    intervention_id,
    client_id,
    org_id,
    phone_formatted: phone,
    salutation,
    whatsapp_body: `${salutation},\n\nMerci pour votre confiance ! L'équipe Mayer Énergie espère que notre intervention s'est bien passée.\n\nVotre avis compte beaucoup pour nous et nous aide à progresser :\n${trackingPlaceholder}\n\nÀ bientôt !\nL'équipe Mayer Énergie`,
    sms_body: `${salutation}, merci pour votre confiance ! Votre avis compte : ${trackingPlaceholder} - Mayer Énergie`,
    channel: 'whatsapp'
  }
}];

// Injecter le log_id dans le lien de tracking
const items = $input.all();
const REDIRECT_BASE = 'https://odspcxgafcqxjzrarsqf.supabase.co/functions/v1/avis-redirect';

for (const item of items) {
  const logId = item.json.id;
  const prevData = $('Formater données').item.json;

  item.json.whatsapp_body = prevData.whatsapp_body.replace(/log_id=PENDING/g, `log_id=${logId}`);
  item.json.sms_body = prevData.sms_body.replace(/log_id=PENDING/g, `log_id=${logId}`);
  item.json.phone_formatted = prevData.phone_formatted;
  item.json.channel = prevData.channel;
  item.json.log_id = logId;
}

return items;
